const Q_BIOLOGY_1999=[{"id": "objective>Biology>1999>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The habitat of the cysticercus of <span style=\"font-style:italic;\"> Taenia solium </span>is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Alimentary canal of cattle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muscles of pig</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alimentary canal of pig</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muscles of cattle</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cysticercus of <span style=\"font-style:italic;\"> Taenia solium </span>, also known as the pork tapeworm, is a stage in the life cycle of the parasite. This stage of the parasite is typically found in the muscles of pigs, making 'Muscles of pig', the correct answer. <br/> The habitat of the cysticercus of <span style=\"font-style:italic;\"> Taenia solium </span>is the muscle tissue of pigs (the intermediate host). In humans (the definitive host), the cysticerci can also develop in various tissues, including the brain, muscles, and other organs, leading to a condition called cysticercosis.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1999>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organism that has a hydrostatic skeleton is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tilapia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosquito larva</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earthworm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An earthworm has a hydrostatic skeleton. A hydrostatic skeleton is a structure found in many soft-bodied animals consisting of a fluid-filled cavity, the coelom, surrounded by muscles. The pressure of the fluid and action of the surrounding muscles are used to change an organism's shape and produce movement, such as burrowing or swimming.</div>", "topic": "SUPPORT AND MOVEMENT : SUPPORTING TISSUES IN ANIMALS"}, {"id": "objective>Biology>1999>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The possession of scales, laying of eggs with shells and bony structure of the head are characteristics shared by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">birds and reptiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fishes and birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reptiles and fishes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birds and molluscs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds and reptiles share the characteristics of having scales, laying eggs with shells, and having a bony structure of the head. Fishes do not lay eggs with shells, and molluscs do not have a bony structure of the head.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BIRD~~STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>1999>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The group of Arthropods that has no antennae is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Crustacea</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Chilopoda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arachnida</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diplopoda</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Arachnida, which includes spiders, scorpions, mites, and ticks, is the group of Arthropods that does not have antennae. The other groups listed, Crustacea, Chilopoda, and Diplopoda, all have antennae.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>1999>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The structure that is most commonly identified in all living cells under the light microscope is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mitochondrion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloroplast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ribosome</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus is the most commonly identified structure in all living cells under the light microscope. It is the control center of the cell and contains the cell's DNA. The other options, mitochondrion, chloroplast, and ribosome, are also present in cells but are not as easily identifiable under a light microscope due to their smaller size.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1999>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an organ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Guard cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Xylem bundle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blood</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An organ is a group of tissues that work together to perform a specific function or set of functions in an organism's body. The liver is an organ that performs many vital functions, including detoxification, protein synthesis, and production of biochemicals necessary for digestion. The other options, guard cell, xylem bundle, and blood, are not organs. A guard cell is a type of cell found on plant leaves. A xylem bundle is a type of tissue in plants, and blood is a body fluid.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>1999>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled II is used for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tasting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feeling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sucking</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II-Antenna <br/> The structure labelled II is used for feeling. <br/> <img src=\"1999/KTTTRB.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1999>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure labeled III represents the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mandible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">palp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proboscis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labium</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The labium is often called an insect's lower lip. The labium is positioned towards the back of the head and helps hold food in place when the insect feeds. The labium actually represents the fused pair of ancestral second maxillae. <br/> <img src=\"1999/KTTTRB.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1999>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The division of a body into two equal halves along a longitudinal plane is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bilateral symmetry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transverse section</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radial symmetry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">longitudinal section</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The division of a body into two equal halves along a longitudinal plane is called bilateral symmetry. This type of symmetry is seen in organisms like humans, where the left and right sides of the body are mirror images of each other. The other options, transverse section, radial symmetry, and longitudinal section, do not correctly describe this concept.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>1999>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following organisms does each cell combine the function of nutrition, reproduction and growth?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rhizopus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dryopteris</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brachymenium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra is a type of green algae where each cell is capable of carrying out all the life processes independently.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1999>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">They key event in the transition of the amphibians from water to land is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">replacement of the gills with lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possession of webbed limbs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of long hind limbs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possession of tympanic membrane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The replacement of gills with lungs allowed amphibians to breathe in air, which is a necessary adaptation for life on land.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1999>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In plant cells, the chloroplast are located</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inside the cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">outside the protoplasm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">within the vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">within the cytoplasm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cytoplasm is the site where most of the cell's metabolic reactions occur, including photosynthesis, which is carried out by the chloroplasts.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1999>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the woody stems, gaseous exchange takes place through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">micropyles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lenticels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vessels</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In woody stems, gaseous exchange takes place through the lenticels. Lenticels are small, corky pores or narrow slits in the stem of a woody plant that allow direct exchange of gases between the internal tissues and atmosphere through the bark, which is otherwise impermeable to gases.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>1999>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Substance manufactured by the leaves are transported to other parts of the plant through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">companion cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> sieve tubes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cambium</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Substances manufactured by the leaves are transported to other parts of the plant through the phloem. The phloem is the vascular tissue in plants that conducts sugars and other metabolic products downward from the leaves.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>1999>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">After a meal of yam has been digested, the highest concentration of glucose is to be found in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hepatic artery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pulmonary vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hepatic portal vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> posterior vena cava</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After a meal of yam has been digested, the highest concentration of glucose is to be found in the hepatic portal vein. The hepatic portal vein is a blood vessel that carries blood from the gastrointestinal tract, gallbladder, pancreas and spleen to the liver. This blood contains nutrients and toxins extracted from digested contents.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>1999>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dark reaction of photosynthesis involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fixation of carbon (IV) oxide to give six-carbon sugar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixation of carbon (IV) oxide with the help of oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of carbon (IV) oxide to produce glucose using ATP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixation of carbon (IV) oxide on chlorophyll using hydrogen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dark reaction, also known as the Calvin cycle, is a light-independent reaction in photosynthesis. It uses the energy from ATP and NADPH produced in the light-dependent reactions to fix carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) and produce glucose (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>). This process occurs in the stroma of the chloroplast and involves the several steps. <br/>  <br/> The other options are incorrect because: <br/>  <br/> Fixation of carbon (IV) oxide to give six-carbon sugar: This option is incorrect because the dark reaction produces a 3-carbon molecule (G3P), not a 6-carbon sugar. <br/>  <br/> Fixation of carbon (IV) oxide with the help of oxygen: This option is incorrect because the dark reaction does not involve oxygen; it's a light-independent reaction that uses ATP and NADPH produced in the light-dependent reactions. <br/>  <br/> Fixation of carbon (IV) oxide on chlorophyll using hydrogen: This option is incorrect because chlorophyll is involved in the light-dependent reactions, not the dark reaction. Additionally, hydrogen is not directly involved in the carbon fixation process in the dark reaction.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>1999>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mammals acclimatize to reduced oxygen content at high altitudes by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the stimulation of marrow to reduce the amount of erythrocytes produced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the rate at which erythrocytes are destroyed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the stimulation of marrow to produce more erythrocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the break down of the protein portion of the erythrocytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mammals acclimatize to reduced oxygen content at high altitudes by the stimulation of marrow to produce more erythrocytes. Erythrocytes, also known as red blood cells, carry oxygen from the lungs to the rest of the body. When the oxygen content is reduced, the body responds by producing more erythrocytes to increase the oxygen-carrying capacity of the blood.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1999>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The modes of nutrition in Nitrobacter, Ascaris and Homo sapiens respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">photosynthetic , parasitic and holozoic</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> chemosynthetic, parasitic and holozoic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthetic, parasitic and heterophytic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemosynthetic, holophytic and holozoic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The modes of nutrition in Nitrobacter, Ascaris and Homo sapiens respectively are chemosynthetic, parasitic and holozoic. Nitrobacter is a type of bacteria that obtains energy by oxidizing nitrite into nitrate, a process known as chemosynthesis. Ascaris, a type of parasitic worm, obtains nutrients by feeding on the host's blood and tissues. Homo sapiens, or humans, have a holozoic mode of nutrition, which involves the ingestion of complex organic substances that are then broken down into simpler substances through digestion.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>1999>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The richest source of vitamin A are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">palm oil and groundnut oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">palm oil and carrot</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> rice and groundnut oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oranges and carrot</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vitamin A is a fat-soluble vitamin that is good for healthy vision, skin, bones and other tissues in the body. Vitamin A often works as an antioxidant, fighting cell damage, but it also has many other uses. Carrots are rich in beta-carotene, a compound your body changes into vitamin A (retinol). Palm oil is also a good source of beta-carotene. Therefore, the richest sources of vitamin A are palm oil and carrot.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1999>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The force that holds water together in the form of a stream within the xylem tube is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cohesion of water molecules to one another by hydrogen bonds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">force of gravity attacking the water molecules through the hydrogen bonds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attraction between the water and xylem osmotic force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">normal flow of water from the ground with help of gravitational force</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The force that holds water together in the form of a stream within the xylem tube is the cohesion of water molecules to one another by hydrogen bonds. This is known as cohesion-tension theory. The water molecules 'stick' to each other, creating a continuous flow of water from the roots to the leaves. This is possible due to the property of cohesion (attraction between similar types of particles or molecules) and adhesion (attraction between different particles or molecules).</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>1999>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Yellowing of leaves is a symptom associated with deficiency of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iron, calcium and magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen, sulphur and potassium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur, phosphorus and iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium, nitrogen and iron</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Yellowing of leaves, also known as chlorosis, is a symptom associated with deficiency of several nutrients including magnesium, nitrogen and iron. Magnesium is a component of the chlorophyll molecule and its deficiency results in chlorosis. Nitrogen is a major component of amino acids, proteins, and nucleic acids and its deficiency also results in chlorosis. Iron is necessary for chlorophyll synthesis and its deficiency leads to chlorosis.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1999>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lymphatic system of mammals rejoins the blood circulatory system at the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hepatic vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subclavian vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">renal vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">common iliac vein</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lymphatic system drains excess fluid from tissues and returns it to the bloodstream. This system rejoins the blood circulatory system at the subclavian vein. The subclavian vein is a pair of large veins, one on either side of the body, that carry blood from the arms back to the heart.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1999>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In dissection, the rib cage of mammal has to be opened in order to expose the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diaphragm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sternum</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In dissection, the rib cage of a mammal has to be opened in order to expose the heart. The heart is located in the thoracic cavity medial to the lungs and posterior to the sternum. It's surrounded by the rib cage for protection, hence the need to open the rib cage to expose it.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>1999>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fertilization in humans usually takes place in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lower part of the uterus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upper part of the uterus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower part of the oviduct</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upper part of the oviduct</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fertilization in humans usually takes place in the upper part of the oviduct, also known as the fallopian tube. After ovulation, the egg is swept into the fallopian tube where it can be fertilized if sperm are present.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>1999>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insects visit flowers in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">feed on the nectar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deposit pollen on the stigma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollinate the flowers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transfer pollen from anthers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insects visit flowers primarily to feed on the nectar. This is a form of mutualism where the insect gets food and the flower gets pollinated. While insects do help in pollination, it is not their primary purpose for visiting the flowers. Therefore, the correct answer is 'feed on the nectar'.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1999>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In epigeal germination, the cotyledons are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carried above the ground by the elongation hypocotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pulled underground by the elongating hypocotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> pulled underground by the elongating epicotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carried above the ground by the elongating epicotyl</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In epigeal germination, the cotyledons are carried above the ground by the elongation of the hypocotyl. The hypocotyl is the part of the stem of an embryo plant beneath the stalks of the seed leaves (cotyledons) and directly above the root. Therefore, the correct answer is 'carried above the ground by the elongation hypocotyl'.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>1999>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria multiply rapidly by means of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">budding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fragmentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">binary fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spore formation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria multiply rapidly by means of binary fission. Binary fission is a form of asexual reproduction used by most prokaryotes. In this process, a single cell divides into two identical cells. Therefore, the correct answer is 'binary fission'.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>1999>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence for the perception of smell in mammals is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chemicals → olfactory nerve endings → brain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolved chemicals → nasal sensory cell → brain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemicals → mucus membrane → sensory cells→ brain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolved chemicals → sensory cells → olfactory nerve → brain</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence for the perception of smell in mammals is dissolved chemicals → sensory cells → olfactory nerve → brain</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1999>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled III is for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lubrication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is for insulation.The part of the skin responsible for insulation is the subcutaneous layer (hypodermis). It is the deepest layer of the skin, located beneath the dermis. The hypodermis consists mainly of adipose tissue (fat cells) and connective tissue. It provides insulation by trapping heat, cushioning to protect muscles and bones from impact, and energy storage in the form of fat. The thickness of this layer varies depending on factors like age, sex, and body region.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>1999>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure labelled II is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sweat gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> lymph vessel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood vessel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nerve ending</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is known as sweat gland. The structure is the sweat gland. In a skin structure diagram, the sweat gland appears as a coiled tubular structure located in the dermis. It consists of a coiled secretory portion and a straight or wavy duct that extends to the skin surface, where it opens as a sweat pore.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>1999>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In mammals, the organ which performs digestive and endocrine functions is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gastric gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salivary gland</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pancreas in mammals performs both digestive and endocrine functions. It produces digestive enzymes that help in the breakdown of food. It also produces hormones like insulin and glucagon that regulate blood sugar levels, hence performing endocrine functions.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>1999>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chitin in the exoskeleton of many arthropods is strengthened by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium compounds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organic salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lipids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proteins</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The chitin in the exoskeleton of many arthropods is strengthened by calcium compounds. Chitin is a complex carbohydrate that provides structural support to the exoskeleton. The addition of calcium compounds further hardens and strengthens the exoskeleton.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1999>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled II articulates with III to form </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> sliding joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hinge joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pivot joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ball-and-socket joint</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hinge joint is a type of synovial joint that allows movement primarily in one plane, such as bending (flexion) and straightening (extension). Examples include the elbow joint, which allows flexion and extension of the forearm, the knee joint for bending and straightening the leg, and the ankle joint, which facilitates upward and downward movement of the foot.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1999>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the bones is the radius?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IV-radius. To distinguish between the radius and ulna in a diagram of the forearm: <br/> - Look for the radius's smooth, rounded head at its proximal end, which articulates with the humerus. <br/> - Note the ulna's prominent olecranon process extending towards the elbow. <br/> - Identify the ulnar styloid process at the distal end of the ulna, contrasting with the radius, which articulates with the wrist without a prominent styloid process.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1999>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The construction of dams may lead to an increase in the prevalence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">typhoid fever, measles and yellow fever</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tuberculosis, leprosy and trypanosomiasis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guinea worm, malaria and tuberculosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">malaria, bilharziasis and onchocerciasis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The construction of dams can lead to an increase in the prevalence of diseases such as malaria, bilharziasis, and onchocerciasis. This is because the stagnant water bodies created by dams provide breeding grounds for the vectors of these diseases. Malaria is transmitted by mosquitoes, bilharziasis (also known as schistosomiasis) is caused by a type of flatworm that lives in fresh water, and onchocerciasis (or river blindness) is caused by a type of roundworm that is transmitted by blackflies that breed in fast-flowing rivers and streams.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1999>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Floating microscopic heterotrophs are mostly grouped as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phytoplankton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zooplankton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">microbes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nekton</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Floating microscopic heterotrophs are mostly grouped as zooplankton. Zooplankton are a type of plankton that consists of small animals and the immature stages of larger animals. They are heterotrophic (i.e., they cannot produce their own food) and float in the water column. Phytoplankton, on the other hand, are autotrophic (i.e., they can produce their own food through photosynthesis) and are not included in this group. Microbes and nekton are also not included in this group because they are not necessarily microscopic or floating.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>1999>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Vaccination is carried out in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">check the production of poison</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the activity of white blood cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the number of red blood cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stimulate the production of antibodies</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vaccination is carried out in order to stimulate the production of antibodies. When a vaccine, which contains a weakened or dead form of a pathogen or its toxins, is introduced into the body, the immune system responds by producing antibodies. These antibodies can recognize and neutralize the pathogen if it enters the body in the future, thereby providing immunity against the disease caused by the pathogen.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1999>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A soil consisting of alumina and iron (II)oxide is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loamy soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clayey soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">laterite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">podzol</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Laterite is a soil type rich in iron and aluminium, and is commonly considered to have formed in hot and wet tropical areas. Nearly all laterites are of rusty-red coloration, because of high iron oxide content. They develop by intensive and prolonged weathering of the underlying parent rock.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>1999>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sign + is used to indicate an association where an organism gains, while 0 is used where an organism is unaffected. An association indicated as +0 is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">predation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commensalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commensalism is a type of relationship where one organism benefits while the other is unaffected. This is represented by the +0 symbol. The organism that benefits is called the commensal while the organism that is unaffected is called the host.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>1999>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The biomass is likely to increase in the sequence </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1→2→4→5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1→3→4→5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3→5→6→7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5→4→3→1</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The biomass is likely to increase in the sequence of 5→4→3→1</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1999>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Primary consumers are found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1, 2 and 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1, 3 and 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3 and 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 4 and 5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Primary consumers in the diagram are found in 2, 3 and 7</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1999>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following characterizes the white mangrove?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prop roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Buttress roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Breathing roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stilt roots</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">White mangroves are characterized by their breathing roots, also known as pneumatophores. These roots protrude from the ground and help the plant to breathe, as they often grow in waterlogged soils where oxygen is scarce.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1999>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the offspring of a cross between a brown mouse (bb) and a black mouse (BB) are allowed to interbreed, how many different genotypes would result?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They will form three different genotypes. The BB is same as B while the bb is same as b so in the first filal generation, <br/> B * b <br/> Bb ( first filal generation) <br/> So. Bb * Bb <br/> BB Bb Bb bb ( second filal generatio) <br/> So three genotypes ( BB, Bb and bb) are formed</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1999>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The biological factor that is unique to each individual is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">DNA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eye colour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RNA</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">DNA is unique to each individual. While eye color, blood group, and RNA can vary among individuals, they are not unique identifiers. DNA, on the other hand, contains the genetic code that determines all of an individual's physical traits and is different for each individual, except for identical twins.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>1999>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From evolutionary standpoint , the older a fossil-bearing rocks is, the more likely it is to contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aves as opposed to amphibians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invertebrates as opposed to vertebrates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">angiosperms as opposed to algae</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> vertebrates as opposed to invertebrates</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From an evolutionary standpoint, the older a fossil-bearing rock is, the more likely it is to contain invertebrates as opposed to vertebrates. This is because invertebrates evolved before vertebrates in the history of life on Earth. Therefore, older rocks are more likely to contain fossils of invertebrates, the first complex organisms to evolve.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>1999>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The very bright colours in some types of mushroom</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are warning that they may be poisonous</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> indicate they are very taste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attract potential transporters of the spores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perform the same function as bright colours in flowers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bright colors in some types of mushrooms serve as a warning signal to potential predators that they may be poisonous. This is a form of aposematism, a biological phenomenon where a species develops conspicuous markings or colors as a warning to predators that it is harmful or unpalatable.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1999>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The least adaptive feature of aboreal life is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">possession of four limbs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possession of claws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of long tail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">counter shading of coat colour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The least adaptive feature of arboreal life is the counter shading of coat colour.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1999>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is one of Lamarck's theories?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Some variations are more favourable to existence in a given environment than others</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All living organisms are constantly involved in a struggle to existence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The size of a given population remains fairly constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">New species originates through the inheritance of acquired traits</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of Lamarck's theories is that new species originate through the inheritance of acquired traits. This is known as Lamarckism or Lamarckian inheritance. According to this theory, an organism can change during its lifetime in response to its environment, and those changes are then passed on to its offspring. This theory has largely been discredited in modern evolutionary biology in favor of Darwinian natural selection.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>1999>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The loud cry made by a brooding hen when a predator is around is meant to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alert the poultry attendants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attract cocks to come and fight the predator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertise the boundaries of its territory to intruders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warn its chicks and other chickens of impending danger</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The loud cry made by a brooding hen when a predator is around is meant to warn its chicks and other chickens of impending danger. This is a common behavior in many bird species, known as alarm calling. The purpose of this behavior is to alert other members of the group to the presence of a potential threat.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1999>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important environment factor which epiphytes in the rain forest compete for is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">space</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Epiphytes are plants that grow on other plants, but do not take nutrients from them. They are often found in rainforests where they can reach the light by growing on taller trees. Therefore, the most important environmental factor they compete for is light. Without sufficient light, they cannot perform photosynthesis effectively.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}];
